import React from "react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";

export default function BusCharts({ history }) {
  // Convert timestamp to readable time
  const data = history.map(item => ({
    time: new Date(item.time * 1000).toLocaleTimeString(),
    Running: item.running,
    Ghost: item.ghost,
    Anomaly: item.anomaly
  }));

  return (
    <div style={{
      position: "absolute",
      top: 60,
      left: 50,
      width: 500,
      height: 300,
      background: "rgba(255,255,255,0.95)",
      borderRadius: "8px",
      boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
      padding: "8px",
      zIndex: 1000
    }}>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="time" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="Running" stroke="green" />
          <Line type="monotone" dataKey="Ghost" stroke="red" />
          <Line type="monotone" dataKey="Anomaly" stroke="orange" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
